mapper.select:
/*AcenCnsltHistMapper.getAcenCnsltSrList*/
SELECT TO_CHAR(MST.TALK_DT, 'YYYY-MM-DD') AS TALK_DT ,FN_GET_CODENM('ACEN0010', MST.TALK_TYPE) AS TALK_TYPE ,DTL.CONTRACT_NUM ,SUB.SUB_LINK_NAME AS CUSTOMER_NM ,MST.CNSLT_TYPE_FIR_NM ,MST.CNSLT_TYPE_SEC_NM ,MST.CNSLT_TYPE_THI_NM ,MST.CNSLT_TYPE_DTL_NM ,NVL2(DTL.OPEN_AGNT_CD, FN_GET_ORGNM(DTL.OPEN_AGNT_CD) || '/' || DTL.OPEN_AGNT_CD, '') AS OPEN_AGNT ,FN_GET_CODENM('MSP0003', DTL.SUB_STATUS) AS SUB_STATUS_NM ,TO_CHAR(TO_DATE(DTL.LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE ,FN_GET_CODENM('RCP9001', DTL.OPER_TYPE) AS OPER_TYPE ,FN_GET_CODENM('RCP9004', DTL.REQ_BUY_TYPE) AS REQ_BUY_TYPE ,FN_GET_USRNM(MST.CNSLT_MID) AS CNSLT_NM FROM NMCP_ACEN_CNSLT_MST@DL_MCP MST ,NMCP_ACEN_CNSLT_DTL@DL_MCP DTL ,MSP_JUO_SUB_INFO SUB ,MSP_RATE_MST RATE WHERE MST.CNSLT_SEQ = DTL.CNSLT_SEQ AND DTL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND DTL.RATE_CD = RATE.RATE_CD(+) AND MST.TALK_DT BETWEEN TO_DATE(#{callStrtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{callEndDt} || '235959', 'YYYYMMDDHH24MISS') AND MST.TALK_YM BETWEEN SUBSTR(#{callStrtDt}, 1, 6) AND SUBSTR(#{callEndDt}, 1, 6) /*상담사ID*/
AND MST.CNSLT_ID = #{searchCnsltId}
/*SR(대)*/
AND MST.CNSLT_TYPE_FIR_NM LIKE '%' || #{searchSrFir} || '%'
/*SR(중)*/
AND MST.CNSLT_TYPE_SEC_NM LIKE '%' || #{searchSrSec} || '%'
/*SR(소)*/
AND MST.CNSLT_TYPE_THI_NM LIKE '%' || #{searchSrThi} || '%'
/*SR(세)*/
AND MST.CNSLT_TYPE_DTL_NM LIKE '%' || #{searchSrDtl} || '%'
/*통화유형*/
AND MST.TALK_TYPE = #{searchTalkType}
/*검색구분(계약번호)*/
AND (DTL.CONTRACT_NUM = #{searchVal} OR DTL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchVal}))
/*검색구분-CTN*/
AND SUB.SUBSCRIBER_NO = #{searchVal}
/*검색구분-요금제*/
AND RATE.RATE_NM LIKE '%' || #{searchVal} || '%'
/*검색구분-고객명*/
AND UPPER(SUB.SUB_LINK_NAME) LIKE UPPER(#{searchVal}) || '%'
ORDER BY MST.TALK_DT DESC, MST.CNSLT_SEQ DESC

/*AcenCnsltHistMapper.getAcenCnsltSrStatsList*/
SELECT TO_CHAR(TO_DATE(TALK_YM, 'YYYYMM'), 'YYYY-MM') AS TALK_YM ,CNSLT_TYPE_FIR_NM ,CNSLT_TYPE_SEC_NM ,CNSLT_TYPE_THI_NM ,CNSLT_TYPE_DTL_NM ,COUNT(CNSLT_SEQ) AS TOTAL_CNT FROM NMCP_ACEN_CNSLT_MST@DL_MCP WHERE TALK_DT BETWEEN TO_DATE(#{strtDttm} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDttm} || '235959', 'YYYYMMDDHH24MISS') AND TALK_YM BETWEEN #{strtDt} AND #{endDt} /*SR(대)*/
AND CNSLT_TYPE_FIR_NM LIKE '%' || #{searchSrFir} || '%'
/*SR(중)*/
AND CNSLT_TYPE_SEC_NM LIKE '%' || #{searchSrSec} || '%'
/*SR(소)*/
AND CNSLT_TYPE_THI_NM LIKE '%' || #{searchSrThi} || '%'
/*상세*/
AND CNSLT_TYPE_DTL_NM LIKE '%' || #{searchSrDtl} || '%'
GROUP BY TALK_YM, CNSLT_TYPE_FIR_NM, CNSLT_TYPE_SEC_NM, CNSLT_TYPE_THI_NM, CNSLT_TYPE_DTL_NM ORDER BY TALK_YM DESC
